#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
int t,n;
ll f[21][4];
void solve(){
    f[0][0]=1;
    for(int i=1;i<20;i++){
        f[i][0]=9*(f[i-1][0]+f[i-1][1]+f[i-1][2]);
        f[i][1]=f[i-1][0];
        f[i][2]=f[i-1][1];
        f[i][3]=f[i-1][2]+10*f[i-1][3];
    }
}
int main(){
    solve();
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        int m=3;
        while(f[m][3]<n)
            m++;
        for(int i=m,k=0;i;i--){
            for(int j=0;j<10;j++){
                ll cnt=f[i-1][3];
                if(j==6 || k==3)
                    for(int l=max(3-k-(j==6),0);l<3;l++)
                        cnt+=f[i-1][l];
                if(cnt<n)
                    n-=cnt;
                else{
                    if(k<3){
                        if(j==6)
                            k++;
                        else
                            k=0;
                    }
                    printf("%d",j);
                    break;
                }
            }
        }
        puts("");
    }
    return 0;
}
